function myAtoi(s) {
  s = s.trim();
  if (!s) return 0;

  let sign = 1, i = 0;
  if (s[0] === '-' || s[0] === '+') {
    sign = s[0] === '-' ? -1 : 1;
    i++;
  }

  let result = 0;
  while (i < s.length && s[i] >= '0' && s[i] <= '9') {
    result = result * 10 + (s[i] - '0');
    i++;
  }

  result *= sign;
  const INT_MAX = 2**31 - 1, INT_MIN = -(2**31);
  if (result > INT_MAX) return INT_MAX;
  if (result < INT_MIN) return INT_MIN;
  return result;
}
